import { createContext, useContext, useState } from 'react';

const CartContext = createContext();

export function CartProvider({ children }) {
  const [cart, setCart] = useState({});

  const addItem = (id, name, price, emoji) => {
    setCart(prev => ({
      ...prev,
      [id]: { name, price, emoji, qty: (prev[id]?.qty || 0) + 1 }
    }));
  };

  const removeItem = (id) => {
    setCart(prev => {
      const updated = { ...prev };
      if (updated[id]) {
        updated[id] = { ...updated[id], qty: updated[id].qty - 1 };
        if (updated[id].qty <= 0) delete updated[id];
      }
      return updated;
    });
  };

  const clearCart = () => setCart({});

  const totalItems = Object.values(cart).reduce((s, i) => s + i.qty, 0);
  const subtotal   = Object.values(cart).reduce((s, i) => s + i.price * i.qty, 0);

  return (
    <CartContext.Provider value={{ cart, addItem, removeItem, clearCart, totalItems, subtotal }}>
      {children}
    </CartContext.Provider>
  );
}

export const useCart = () => useContext(CartContext);
